// Prepare scene data for sliding window processing
const scenes = $('Load Pending Scenes').first().json;
const topicId = $('Webhook Trigger').item.json.body.topic_id;

if (!Array.isArray(scenes) || scenes.length === 0) {
  return [{
    json: {
      scenes: [],
      topic_id: topicId,
      total_scenes: 0,
      scenes_completed: 0,
      scenes_failed: 0,
      total_image_cost: 0,
      skip_processing: true
    }
  }];
}

return [{
  json: {
    scenes: scenes,
    topic_id: scenes[0].topic_id,
    project_id: scenes[0].project_id,
    total_scenes: scenes.length,
    scenes_completed: 0,
    scenes_failed: 0,
    total_image_cost: 0,
    skip_processing: false
  }
}];

// Sliding Window Image Generation - 5 concurrent slots
// Uses Kie.ai Seedream 4.5 async API: POST createTask -> poll recordInfo

const data = $input.first().json;
const scenes = data.scenes;
const topicId = data.topic_id;
const projectId = data.project_id;

const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_ANON_KEY = $env.SUPABASE_ANON_KEY;
const SUPABASE_SERVICE_ROLE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
const KIE_API_KEY = $env.KIE_API_KEY;
const N8N_WEBHOOK_BASE = $env.N8N_WEBHOOK_BASE;
const DASHBOARD_API_TOKEN = $env.DASHBOARD_API_TOKEN;

const MAX_CONCURRENT = 5;
const POLL_INTERVAL_MS = 3000;
const MAX_RETRIES = 3;
const BACKOFF_MS = [30000, 60000, 120000];
const COST_PER_IMAGE = 0.032;

const supabaseHeaders = {
  'apikey': SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

const kieHeaders = {
  'Authorization': `Bearer ${KIE_API_KEY}`,
  'Content-Type': 'application/json'
};

function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

// Check if topic is stopped
async function isTopicStopped() {
  try {
    const resp = await fetch(
      `${SUPABASE_URL}/rest/v1/topics?id=eq.${topicId}&select=status`,
      { headers: supabaseHeaders }
    );
    const result = await resp.json();
    return result[0]?.status === 'stopped';
  } catch (e) {
    return false;
  }
}

// Submit image generation task to Kie.ai
async function submitTask(scene) {
  const resp = await fetch('https://api.kie.ai/api/v1/jobs/createTask', {
    method: 'POST',
    headers: kieHeaders,
    body: JSON.stringify({
      model: 'seedream/seedream-4.5-text-to-image',
      input: {
        prompt: scene.image_prompt,
        aspect_ratio: '16:9',
        quality: 'basic'
      }
    })
  });
  const result = await resp.json();
  if (result.code === 200 && result.data?.taskId) {
    return result.data.taskId;
  }
  throw new Error(`Kie.ai createTask failed: ${JSON.stringify(result)}`);
}

// Poll task result
async function pollTask(taskId) {
  const resp = await fetch(
    `https://api.kie.ai/api/v1/jobs/recordInfo?taskId=${taskId}`,
    { headers: kieHeaders }
  );
  const result = await resp.json();
  if (result.code === 200 && result.data) {
    return result.data;
  }
  throw new Error(`Kie.ai pollTask failed: ${JSON.stringify(result)}`);
}

// Upload image URL to Google Drive (via n8n sub-workflow or direct API)
// For now, store the Kie.ai result URL directly and mark for Drive upload
async function updateSceneSuccess(sceneId, imageUrl) {
  await fetch(
    `${SUPABASE_URL}/rest/v1/scenes?id=eq.${sceneId}`,
    {
      method: 'PATCH',
      headers: { ...supabaseHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({
        image_status: 'uploaded',
        image_url: imageUrl
      })
    }
  );
}

async function updateSceneFailed(sceneId, errorMsg) {
  await fetch(
    `${SUPABASE_URL}/rest/v1/scenes?id=eq.${sceneId}`,
    {
      method: 'PATCH',
      headers: { ...supabaseHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({
        image_status: 'failed'
      })
    }
  );
}

// Update topic cost tracking
async function updateTopicCost(costIncrement) {
  // Read current cost_breakdown
  const resp = await fetch(
    `${SUPABASE_URL}/rest/v1/topics?id=eq.${topicId}&select=cost_breakdown,total_cost`,
    { headers: supabaseHeaders }
  );
  const topics = await resp.json();
  const current = topics[0] || {};
  const breakdown = current.cost_breakdown || {};
  const currentImageCost = breakdown.images || 0;
  const currentTotal = current.total_cost || 0;

  await fetch(
    `${SUPABASE_URL}/rest/v1/topics?id=eq.${topicId}`,
    {
      method: 'PATCH',
      headers: { ...supabaseHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({
        cost_breakdown: { ...breakdown, images: currentImageCost + costIncrement },
        total_cost: currentTotal + costIncrement
      })
    }
  );
}

// Main sliding window loop
let pending = [...scenes];
let active = []; // { scene, taskId, retries }
let completed = 0;
let failed = 0;
let totalCost = 0;
let stopped = false;

while ((pending.length > 0 || active.length > 0) && !stopped) {
  // Check stop
  if (await isTopicStopped()) {
    stopped = true;
    break;
  }

  // Fill slots up to MAX_CONCURRENT
  while (active.length < MAX_CONCURRENT && pending.length > 0) {
    const scene = pending.shift();
    try {
      const taskId = await submitTask(scene);
      active.push({ scene, taskId, retries: 0, submittedAt: Date.now() });
    } catch (err) {
      // Submission failed - retry logic
      if ((scene._retries || 0) < MAX_RETRIES) {
        scene._retries = (scene._retries || 0) + 1;
        const backoffMs = BACKOFF_MS[scene._retries - 1] || BACKOFF_MS[2];
        await sleep(backoffMs);
        pending.unshift(scene); // Re-add to front of queue
      } else {
        await updateSceneFailed(scene.id, err.message);
        failed++;
      }
    }
  }

  // Wait before polling
  await sleep(POLL_INTERVAL_MS);

  // Poll all active slots
  const stillActive = [];
  for (const slot of active) {
    try {
      const result = await pollTask(slot.taskId);
      const state = result.state || result.status;

      if (state === 'success') {
        // Extract image URL from result
        let imageUrl = null;
        if (result.resultJson) {
          const parsed = typeof result.resultJson === 'string' ? JSON.parse(result.resultJson) : result.resultJson;
          imageUrl = parsed.resultUrls?.[0] || parsed.url || null;
        }
        if (!imageUrl && result.resultUrls) {
          imageUrl = result.resultUrls[0];
        }

        if (imageUrl) {
          await updateSceneSuccess(slot.scene.id, imageUrl);
          await updateTopicCost(COST_PER_IMAGE);
          completed++;
          totalCost += COST_PER_IMAGE;
        } else {
          // Success but no URL - treat as failure
          await updateSceneFailed(slot.scene.id, 'No image URL in success response');
          failed++;
        }
      } else if (state === 'fail' || state === 'failed') {
        if (slot.retries < MAX_RETRIES) {
          slot.retries++;
          const backoffMs = BACKOFF_MS[slot.retries - 1] || BACKOFF_MS[2];
          await sleep(backoffMs);
          try {
            const newTaskId = await submitTask(slot.scene);
            stillActive.push({ ...slot, taskId: newTaskId, submittedAt: Date.now() });
          } catch (retryErr) {
            await updateSceneFailed(slot.scene.id, retryErr.message);
            failed++;
          }
        } else {
          await updateSceneFailed(slot.scene.id, `Failed after ${MAX_RETRIES} retries`);
          failed++;
        }
      } else {
        // Still processing (waiting, queuing, generating)
        stillActive.push(slot);
      }
    } catch (pollErr) {
      // Poll error - keep in active for next cycle
      stillActive.push(slot);
    }
  }
  active = stillActive;
}

return [{
  json: {
    topic_id: topicId,
    project_id: projectId,
    completed,
    failed,
    total_cost: totalCost,
    stopped
  }
}];

// Parallel completion sync: check if ALL visual scenes are done
// If this is the last visual workflow to finish, claim assembly

const data = $input.first().json;
const topicId = data.topic_id;

const SUPABASE_URL = $env.SUPABASE_URL;
const supabaseHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

// If we were stopped, skip completion sync
if (data.stopped) {
  return [{ json: { ...data, assembly_claimed: false, reason: 'stopped' } }];
}

// Count completed visual scenes (uploaded or skipped)
const completedResp = await fetch(
  `${SUPABASE_URL}/rest/v1/scenes?topic_id=eq.${topicId}&or=(image_status.eq.uploaded,video_status.eq.uploaded,skipped.eq.true)&select=id`,
  { headers: supabaseHeaders }
);
const completedScenes = await completedResp.json();
const completedCount = Array.isArray(completedScenes) ? completedScenes.length : 0;

// Count total visual scenes
const totalResp = await fetch(
  `${SUPABASE_URL}/rest/v1/scenes?topic_id=eq.${topicId}&visual_type=in.(static_image,i2v,t2v)&select=id`,
  { headers: supabaseHeaders }
);
const totalScenes = await totalResp.json();
const totalCount = Array.isArray(totalScenes) ? totalScenes.length : 0;

let assemblyClaimed = false;

if (completedCount >= totalCount && totalCount > 0) {
  // Try to atomically claim assembly
  const claimResp = await fetch(
    `${SUPABASE_URL}/rest/v1/topics?id=eq.${topicId}&assembly_status=eq.pending`,
    {
      method: 'PATCH',
      headers: { ...supabaseHeaders, 'Prefer': 'return=representation' },
      body: JSON.stringify({ assembly_status: 'starting' })
    }
  );
  const claimResult = await claimResp.json();
  assemblyClaimed = Array.isArray(claimResult) && claimResult.length > 0;
}

return [{
  json: {
    ...data,
    completed_visual_scenes: completedCount,
    total_visual_scenes: totalCount,
    assembly_claimed: assemblyClaimed
  }
}];
